mapper.select:
SELECT int_job_dept_cd
FROM bpm_node_department
WHERE int_job_dept_name = #{deptName}
  AND org_level = #{orgLevel}

      AND int_job_branch = #{intJobBranch}


      AND int_job_cen_branch = #{intJobCenBranch}


      AND int_job_busi_branch = #{intJobBusiBranch}

  AND delete_flag = '0'
LIMIT 1
